// ============================================================
// REDACT VICTIM DATA — RUNS FIRST
// ============================================================
// This node runs IMMEDIATELY after fetching raw data.
// It redacts victim names, domains, and URLs before any
// other node can display them in the n8n UI.
//
// IMPORTANT: This ensures no real victim names appear
// anywhere in the workflow execution history, logs, or
// screenshots during the SANS webinar.
// ============================================================

const FAKE_COMPANIES = [
  'Apex Industrial Solutions', 'Meridian Health Partners',
  'Cobalt Financial Group', 'Zenith Technologies Inc',
  'Pinnacle Energy Corp', 'Vanguard Public Services',
  'Atlas Manufacturing Ltd', 'Horizon Medical Systems',
  'Sterling Capital Advisors', 'Quantum Dynamics Corp',
  'Ironbridge Logistics', 'Cascade Healthcare Network',
  'Summit Engineering Group', 'Pacific Rim Trading Co',
  'Northwind Aerospace', 'Redwood Pharmaceuticals',
  'Clearwater Data Systems', 'Titan Defense Industries',
  'Evergreen Supply Chain', 'Beacon Analytics Group'
];

let fakeIndex = 0;

function nextFakeName() {
  const name = FAKE_COMPANIES[fakeIndex % FAKE_COMPANIES.length];
  fakeIndex++;
  return name;
}

const items = $input.all();
const redacted = [];

for (const item of items) {
  const v = item.json;
  redacted.push({
    json: {
      victim_redacted: nextFakeName(),
      group: v.group || 'Unknown',
      activity: v.activity || '',
      country: v.country || 'Unknown',
      discovered: v.discovered || '',
      attackdate: v.attackdate || '',
      description: v.description || '',
      infostealer: v.infostealer || false,
      press: v.press || false,
      domain: '[REDACTED]',
      url: '[REDACTED]',
      claim_url: '[REDACTED]',
      screenshot: '[REDACTED]'
    }
  });
}

return redacted;

// ============================================================
// FILTER BY INDUSTRY (activity field)
// ============================================================
// The ransomware.live API uses the 'activity' field for
// sector/industry classification. This node filters to
// only the industries relevant to our audience.
//
// Customize the targetIndustries array to match your
// organization or the demo you want to show.
// ============================================================

const targetIndustries = [
  'manufacturing',
  'healthcare',
  'health',
  'hospital',
  'medical',
  'finance',
  'financial',
  'banking',
  'insurance',
  'technology',
  'software',
  'IT services',
  'energy',
  'oil',
  'utilities',
  'government',
  'education',
  'construction',
  'legal',
  'retail',
  'transportation',
  'logistics'
];

const items = $input.all();
const filtered = [];

for (const item of items) {
  const activity = (item.json.activity || '').toLowerCase();

  if (!activity) continue;

  const matches = targetIndustries.some(ind =>
    activity.includes(ind.toLowerCase())
  );

  if (matches) {
    filtered.push(item);
  }
}

if (filtered.length === 0) {
  return [{ json: { message: 'No victims found in target industries', count: 0 } }];
}

return filtered;

// ============================================================
// EXTRACT UNIQUE THREAT GROUPS
// ============================================================
// Deduplicate ransomware groups and collect their victim
// lists so we fetch each group profile only once.
// ============================================================

const items = $input.all();

if (items.length === 1 && items[0].json.count === 0) {
  return [{ json: { no_results: true, message: items[0].json.message } }];
}

const groupMap = {};

for (const item of items) {
  const group = item.json.group;
  if (group && group !== 'Unknown') {
    if (!groupMap[group]) {
      groupMap[group] = [];
    }
    groupMap[group].push({
      victim_redacted: item.json.victim_redacted,
      activity: item.json.activity,
      country: item.json.country,
      discovered: item.json.discovered,
      attackdate: item.json.attackdate
    });
  }
}

const groups = Object.entries(groupMap).map(([name, victims]) => ({
  json: {
    group: name,
    victim_count: victims.length,
    victims: victims
  }
}));

return groups.length > 0
  ? groups
  : [{ json: { no_results: true, message: 'No groups identified' } }];

// ============================================================
// BUILD CONSOLIDATED THREAT BRIEF
// ============================================================
// Aggregates ALL group profiles + victim data into ONE
// single document. Outputs three formats:
//   - markdown:   for Slack / raw display
//   - plain_text: for Google Docs
//   - slack_text: condensed Slack message
//
// This replaces the old per-group output that was creating
// 20 separate documents.
// ============================================================

const items = $input.all();
const now = new Date().toISOString().split('T')[0];

// ---- Collect all group data with their victims ----
const groupBriefs = [];
let totalVictims = 0;

for (const item of items) {
  const profile = item.json;
  const groupName = (profile.name || profile.group || 'Unknown').toUpperCase();

  // Recover victim list from the earlier node via the input chain
  // The HTTP Request node returns group profile data but we also
  // need the victim context we attached earlier. n8n preserves
  // paired data when items flow 1:1, so $('Extract Unique Groups')
  // gives us the matching item.
  let victims = [];
  try {
    const pairedData = $('Extract Unique Groups').item;
    if (pairedData && pairedData.json && pairedData.json.victims) {
      victims = pairedData.json.victims;
      totalVictims += victims.length;
    }
  } catch (e) {
    // Fallback: no paired data available
  }

  groupBriefs.push({
    name: groupName,
    description: profile.description || '',
    locations: profile.locations || 'Unknown',
    profile_notes: profile.profile || [],
    victims: victims
  });
}

// ---- Build Markdown ----
let md = `# Ransomware Threat Brief\n`;
md += `**Date:** ${now} | **Groups:** ${groupBriefs.length} | **Victims (filtered):** ${totalVictims}\n\n`;
md += `---\n\n`;

// Executive summary table
md += `## Threat Overview\n\n`;
md += `| Group | Victims | Industries Hit | Countries |\n`;
md += `|-------|---------|---------------|-----------|\n`;

for (const g of groupBriefs) {
  const industries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].join(', ') || 'N/A';
  const countries = [...new Set(g.victims.map(v => v.country).filter(Boolean))].join(', ') || 'N/A';
  md += `| ${g.name} | ${g.victims.length} | ${industries} | ${countries} |\n`;
}

md += `\n---\n\n`;

// Per-group deep dive
for (const g of groupBriefs) {
  md += `## ${g.name}\n\n`;

  if (g.description) {
    md += `${g.description.substring(0, 400)}\n\n`;
  }

  md += `**Suspected Location:** ${g.locations}\n\n`;

  if (g.profile_notes && g.profile_notes.length > 0) {
    const notes = Array.isArray(g.profile_notes) ? g.profile_notes : [g.profile_notes];
    for (const note of notes) {
      if (note && typeof note === 'string') {
        md += `> ${note.substring(0, 250)}\n`;
      }
    }
    md += `\n`;
  }

  if (g.victims.length > 0) {
    md += `**Recent Targets (redacted):**\n\n`;
    md += `| Company (Redacted) | Industry | Country | Discovered |\n`;
    md += `|--------------------|----------|---------|------------|\n`;
    for (const v of g.victims) {
      md += `| ${v.victim_redacted} | ${v.activity || 'N/A'} | ${v.country || 'N/A'} | ${v.discovered || 'N/A'} |\n`;
    }
    md += `\n`;
  }

  md += `---\n\n`;
}

md += `\n_Monitor powered by ransomware.live API + n8n_\n`;
md += `_SANS Webinar Demo — AI-Powered Ransomware Intelligence_\n`;
md += `_All victim names have been redacted for this presentation._\n`;

// ---- Build Slack summary (condensed) ----
let slack = `*Ransomware Threat Brief — ${now}*\n`;
slack += `${groupBriefs.length} active groups | ${totalVictims} victims in monitored industries\n\n`;

for (const g of groupBriefs) {
  const industries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].slice(0, 3).join(', ');
  slack += `*${g.name}* — ${g.victims.length} victim(s) | ${industries}\n`;
}

slack += `\n_All victim names redacted. Full brief in Google Doc._`;

// ---- Build plain text for Google Docs ----
let plain = md.replace(/\*\*/g, '').replace(/^#+\s/gm, '').replace(/\|/g, ' | ');

return [{
  json: {
    markdown: md,
    slack_text: slack,
    google_doc_content: plain,
    group_count: groupBriefs.length,
    victim_count: totalVictims,
    generated_at: now
  }
}];

// No groups found in monitored industries — log it
return [{
  json: {
    status: 'clear',
    message: 'No ransomware activity detected in monitored industries this cycle.',
    timestamp: new Date().toISOString()
  }
}];
